/* Cascade-layer order: AeVox sits below Tailwind's components/utilities so its
   global reset and component classes never outrank Tailwind utilities. */
@layer theme, base, aevox, components, utilities, aevox-overrides;

@import "tailwindcss";
@import "tw-animate-css";
/* Fonts load via <link> in index.html (Google Fonts) — keeps @import order
   valid under Tailwind v4. */

/* AeVox tokens — ONE drop-in file. Tokens are stored as HSL channels (e.g.
   `214 29% 17%`) so Tailwind's alpha modifiers work (text-ink-2/40). Light is
   the DEFAULT (:root); `.dark` flips it (the shadcn/Tailwind v4 convention). */
@layer aevox {
/* ---- LIGHT (the default) ---- */
:root {
  /* Surfaces — elevation ladder (canvas → cards). */
  --surface-0: 218 31% 95%;   /* #eef1f6 app canvas */
  --surface-1: 0 0% 100%;     /* #ffffff chrome */
  --surface-2: 0 0% 100%;     /* #ffffff cards */
  --surface-3: 217 40% 96%;   /* #f1f4f9 raised / hover */
  --surface-4: 215 33% 93%;   /* #e7ecf3 active / input */

  /* Borders */
  --line: 216 26% 93%;        /* #e7ebf1 */
  --line-2: 216 24% 88%;      /* #d8dee7 */
  --line-3: 213 20% 78%;      /* #bcc6d2 */

  /* Text ladder */
  --ink-1: 214 29% 17%;       /* #1f2a38 */
  --ink-2: 214 17% 36%;       /* #4c5a6c */
  --ink-3: 213 14% 60%;       /* #8a97a7 */
  --ink-4: 217 16% 71%;       /* #aab3c1 */

  /* Accent — cyan (single brand accent) */
  --accent: 190 90% 38%;      /* #0a9cb8 */
  --accent-2: 190 88% 33%;    /* #0a87a0 */
  --accent-deep: 190 86% 27%; /* #0a6d82 */
  --accent-ghost: rgba(10, 156, 184, 0.1);
  --accent-ghost-2: rgba(10, 156, 184, 0.18);
  --accent-line: rgba(10, 156, 184, 0.32);
  --accent-glow: rgba(10, 156, 184, 0.3);

  /* Status (light, vivid + AA on white) */
  --live: 172 84% 37%;        /* #0fae9a */
  --live-ghost: rgba(15, 174, 154, 0.12);
  --train: 38 87% 47%;        /* #e0930f */
  --train-ghost: rgba(224, 147, 15, 0.13);
  --warn: 0 75% 59%;          /* #e54848 */
  --warn-ghost: rgba(229, 72, 72, 0.11);
  --idle: 239 84% 67%;        /* #6366f1 */
  --idle-ghost: rgba(99, 102, 241, 0.12);
  --pos: 157 79% 35%;         /* #13a06a */
  --pos-ghost: rgba(19, 160, 106, 0.12);
  --neg: 347 75% 59%;         /* #e5486b */
  --neg-ghost: rgba(229, 72, 107, 0.12);

  /* Demo preview surface */
  --stage: 220 50% 98%;       /* #f6f8fc */

  /* Card elevation — lit-from-above edge + cast shadow */
  --edge: rgba(255, 255, 255, 0.03);
  --sh-card: 0 1px 2px rgba(16, 28, 42, 0.05);
  --sh-card-hi: 0 2px 8px rgba(16, 28, 42, 0.08);

  /* Ambient shadows (light) */
  --sh-1: 0 1px 2px rgba(16, 28, 42, 0.06);
  --sh-2: 0 6px 22px rgba(16, 28, 42, 0.1);
  --sh-3: 0 18px 50px rgba(16, 28, 42, 0.16);
  --sh-glow: 0 0 0 1px rgba(10, 156, 184, 0.22), 0 8px 30px rgba(10, 156, 184, 0.15);

  /* Type / layout (theme-agnostic; radii live in @theme below) */
  --f-display: 'Bricolage Grotesque', sans-serif;
  --f-sans: 'Hanken Grotesk', sans-serif;
  --f-mono: 'IBM Plex Mono', monospace;
  --nav-w: 264px;
  --topbar-h: 60px;
  --glow-on: 1;

  --topbar-bg: hsl(var(--surface-1));
  --overlay-bg: rgba(22, 30, 42, 0.4);
  color-scheme: light;
}

/* ---- DARK (.dark) ---- */
.dark {
  --surface-0: 220 20% 6%;    /* #0c0e12 */
  --surface-1: 223 13% 10%;   /* #17191e */
  --surface-2: 220 14% 13%;   /* #1c1f25 */
  --surface-3: 222 12% 16%;   /* #23262d */
  --surface-4: 218 11% 19%;   /* #2c3037 */

  --line: 222 12% 16%;        /* #24272e */
  --line-2: 220 13% 22%;      /* #313640 */
  --line-3: 219 11% 30%;      /* #434954 */

  --ink-1: 220 19% 94%;       /* #eceef2 */
  --ink-2: 216 8% 63%;        /* #9aa0a9 */
  --ink-3: 216 7% 42%;        /* #646a73 */
  --ink-4: 217 8% 30%;        /* #474c54 */

  --accent: 188 86% 53%;      /* #22d3ee */
  --accent-2: 188 86% 45%;    /* #10bcd8 */
  --accent-deep: 190 90% 38%; /* #0a9cba */
  --accent-ghost: rgba(34, 211, 238, 0.12);
  --accent-ghost-2: rgba(34, 211, 238, 0.2);
  --accent-line: rgba(34, 211, 238, 0.35);
  --accent-glow: rgba(34, 211, 238, 0.45);

  --live: 170 74% 54%;        /* #34e0c4 */
  --live-ghost: rgba(52, 224, 196, 0.13);
  --train: 42 93% 65%;        /* #f9c652 */
  --train-ghost: rgba(249, 198, 82, 0.14);
  --warn: 0 91% 71%;          /* #f87171 */
  --warn-ghost: rgba(248, 113, 113, 0.13);
  --idle: 233 79% 71%;        /* #7c89f0 */
  --idle-ghost: rgba(124, 137, 240, 0.13);
  --pos: 158 64% 52%;         /* #34d399 */
  --pos-ghost: rgba(52, 211, 153, 0.13);
  --neg: 351 95% 71%;         /* #fb7185 */
  --neg-ghost: rgba(251, 113, 133, 0.13);

  --stage: 220 22% 8%;        /* #101319 */

  --edge: rgba(255, 255, 255, 0.03);
  --sh-card: 0 1px 2px rgba(0, 0, 0, 0.22), 0 2px 6px rgba(0, 0, 0, 0.14);
  --sh-card-hi: 0 2px 6px rgba(0, 0, 0, 0.28), 0 8px 22px rgba(0, 0, 0, 0.22);

  --sh-1: 0 1px 3px rgba(0, 0, 0, 0.5);
  --sh-2: 0 8px 28px rgba(0, 0, 0, 0.55);
  --sh-3: 0 24px 60px rgba(0, 0, 0, 0.62);
  --sh-glow: 0 0 0 1px rgba(34, 211, 238, 0.25), 0 8px 30px rgba(34, 211, 238, 0.18);

  --overlay-bg: rgba(3, 5, 9, 0.78);
  color-scheme: dark;
}

:root[data-density="compact"] { --row-h: 46px; --pad-card: 16px; }
:root { --row-h: 56px; --pad-card: 24px; }

@keyframes skel { 0%{background-position:200% 0} 100%{background-position:-200% 0} }
@keyframes fadein { from { opacity: .55; } to { opacity: 1; } }
@keyframes ae-rise { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: none; } }

/* Opt-in reveal — apply to one element deliberately, never the whole page. */
.ae-rise { animation: ae-rise 0.5s cubic-bezier(0.2, 0.7, 0.3, 1) both; }
@media (prefers-reduced-motion: reduce) {
  .ae-rise { animation: none; }
}

/* ---- AeVox-native primitive classes (Sonar / Stat / StatusDot) ---- */
.dot { width: 7px; height: 7px; border-radius: 50%; flex: none; }
.dot.live { background: hsl(var(--live)); }
.dot.train { background: hsl(var(--train)); }
.dot.idle { background: hsl(var(--idle)); }
.dot.warn { background: hsl(var(--warn)); }
.dot.off { background: hsl(var(--ink-3)); }
.sonar { position: relative; display: grid; place-items: center; }
.sonar .core {
  width: 24%; height: 24%; border-radius: 50%;
  background: hsl(var(--accent)); box-shadow: 0 0 12px var(--accent-glow);
}
/* Expanding ping rings — scale 0.28 → 1, so they stay inside the box. */
.sonar .ping {
  position: absolute; width: 100%; height: 100%;
  border-radius: 50%; border: 1.5px solid hsl(var(--accent)); opacity: 0;
  animation: ae-ping 3s cubic-bezier(0.2, 0.55, 0.3, 1) infinite;
}
.sonar .ping.p2 { animation-delay: 1s; }
.sonar .ping.p3 { animation-delay: 2s; }
@media (prefers-reduced-motion: reduce) {
  .sonar .ping { animation: none; opacity: 0.16; transform: scale(0.7); }
}
.stat { display: flex; flex-direction: column; gap: 6px; }
.stat .k { font-size: 12.5px; color: hsl(var(--ink-2)); font-weight: 500; display: flex; align-items: center; gap: 7px; }
.stat .v { font-family: var(--f-display); font-size: 30px; font-weight: 600; letter-spacing: -0.02em; line-height: 1; }
.stat .v small { font-size: 15px; color: hsl(var(--ink-3)); font-weight: 500; }
.stat .v.mono-stat, .stat .v { font-family: var(--f-mono) !important; font-feature-settings: "tnum" 1; font-size: 36px; font-weight: 600; letter-spacing: -.03em; }
}

/* ============================================================
   AeVox ↔ Tailwind v4 ↔ shadcn bridge
   - Tokens (the @layer aevox block above) are the source of truth, stored as
     HSL channels. The shadcn semantic vars pass the channels through; @theme
     wraps them in hsl() so utilities + alpha modifiers both work.
   - Light is the DEFAULT; `.dark` flips it.
   ============================================================ */

@custom-variant dark (&:where(.dark, .dark *));

/* shadcn semantic tokens → AeVox channel tokens (passthrough; @theme wraps). */
:root {
  --background: var(--surface-0);
  --foreground: var(--ink-1);

  --card: var(--surface-2);
  --card-foreground: var(--ink-1);

  --popover: var(--surface-2);
  --popover-foreground: var(--ink-1);

  --primary: var(--accent);
  --primary-foreground: 0 0% 100%; /* light: white on deep cyan */

  --secondary: var(--surface-3);
  --secondary-foreground: var(--ink-1);

  --muted: var(--surface-3);
  --muted-foreground: var(--ink-2);

  --destructive: var(--warn);
  --destructive-foreground: 0 0% 100%;

  --input: var(--line-2);
  --ring: var(--accent);

  --radius: var(--radius-md);
}

/* Dark theme: bright cyan / soft red want DARK ink. */
.dark {
  --primary-foreground: 195 76% 10%;   /* #06222b */
  --destructive-foreground: 0 55% 11%; /* #2a0c0c */
}

@theme inline {
  /* shadcn semantic palette (channels → hsl) */
  --color-background: hsl(var(--background));
  --color-foreground: hsl(var(--foreground));
  --color-card: hsl(var(--card));
  --color-card-foreground: hsl(var(--card-foreground));
  --color-popover: hsl(var(--popover));
  --color-popover-foreground: hsl(var(--popover-foreground));
  --color-primary: hsl(var(--primary));
  --color-primary-foreground: hsl(var(--primary-foreground));
  --color-secondary: hsl(var(--secondary));
  --color-secondary-foreground: hsl(var(--secondary-foreground));
  --color-muted: hsl(var(--muted));
  --color-muted-foreground: hsl(var(--muted-foreground));
  --color-destructive: hsl(var(--destructive));
  --color-destructive-foreground: hsl(var(--destructive-foreground));
  --color-border: hsl(var(--line));
  --color-input: hsl(var(--input));
  --color-ring: hsl(var(--ring));

  /* AeVox raw palette → utilities: bg-surface-2, text-ink-2, text-accent, border-line-2 … */
  --color-surface-0: hsl(var(--surface-0));
  --color-surface-1: hsl(var(--surface-1));
  --color-surface-2: hsl(var(--surface-2));
  --color-surface-3: hsl(var(--surface-3));
  --color-surface-4: hsl(var(--surface-4));
  --color-line: hsl(var(--line));
  --color-line-2: hsl(var(--line-2));
  --color-line-3: hsl(var(--line-3));
  --color-ink-1: hsl(var(--ink-1));
  --color-ink-2: hsl(var(--ink-2));
  --color-ink-3: hsl(var(--ink-3));
  --color-ink-4: hsl(var(--ink-4));
  --color-accent: hsl(var(--accent));
  --color-accent-2: hsl(var(--accent-2));
  --color-accent-deep: hsl(var(--accent-deep));
  --color-accent-ghost: var(--accent-ghost);
  --color-accent-line: var(--accent-line);
  --color-accent-glow: var(--accent-glow);
  --color-live: hsl(var(--live));
  --color-train: hsl(var(--train));
  --color-warn: hsl(var(--warn));
  --color-idle: hsl(var(--idle));
  --color-pos: hsl(var(--pos));
  --color-neg: hsl(var(--neg));

  /* Type */
  --font-display: var(--f-display);
  --font-sans: var(--f-sans);
  --font-mono: var(--f-mono);

  /* Radii (override Tailwind defaults with the AeVox scale) */
  --radius-xs: 6px;
  --radius-sm: 9px;
  --radius-md: 13px;
  --radius-lg: 18px;
  --radius-xl: 26px;
  --radius-pill: 999px;

  /* Shadows */
  --shadow-card: var(--sh-card);
  --shadow-card-hi: var(--sh-card-hi);
  --shadow-1: var(--sh-1);
  --shadow-2: var(--sh-2);
  --shadow-3: var(--sh-3);
  --shadow-glow: var(--sh-glow);
}

@layer base {
  * {
    border-color: hsl(var(--line));
  }
  body {
    background: hsl(var(--surface-0));
    color: hsl(var(--ink-1));
    font-family: var(--f-sans);
    -webkit-font-smoothing: antialiased;
  }
  /* Anything clickable gets the pointer cursor (disabled controls keep theirs). */
  button:not(:disabled),
  [role="button"],
  [role="tab"],
  [role="switch"],
  [role="checkbox"],
  [role="radio"],
  [role="menuitem"],
  [role="menuitemcheckbox"],
  [role="menuitemradio"],
  [role="option"],
  a[href],
  label[for],
  summary {
    cursor: pointer;
  }
}

/* Quality floor: respect reduced motion. */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ============================================================
   AeVox shadcn overrides — sits ABOVE Tailwind utilities so it replaces
   shadcn's transparent/base controls with the AeVox surface language.
   ============================================================ */
@layer aevox-overrides {
  [data-slot="input"],
  [data-slot="textarea"],
  [data-slot="select-trigger"] {
    background-color: hsl(var(--surface-1));
    border-color: hsl(var(--line-2));
    border-radius: var(--radius-sm);
    color: hsl(var(--ink-1));
  }
  [data-slot="input"]:hover,
  [data-slot="textarea"]:hover,
  [data-slot="select-trigger"]:hover {
    border-color: hsl(var(--line-3));
  }
  [data-slot="input"]:focus-visible,
  [data-slot="textarea"]:focus-visible,
  [data-slot="select-trigger"]:focus-visible {
    border-color: var(--accent-line);
    box-shadow: 0 0 0 3px var(--accent-ghost);
  }
  /* Error state — red border + ring. */
  [data-slot="input"][aria-invalid="true"],
  [data-slot="textarea"][aria-invalid="true"],
  [data-slot="select-trigger"][aria-invalid="true"] {
    border-color: hsl(var(--warn));
  }
  [data-slot="input"][aria-invalid="true"]:focus-visible,
  [data-slot="textarea"][aria-invalid="true"]:focus-visible,
  [data-slot="select-trigger"][aria-invalid="true"]:focus-visible {
    border-color: hsl(var(--warn));
    box-shadow: 0 0 0 3px var(--warn-ghost);
  }

  /* Floating surfaces sit ABOVE cards. */
  [data-slot="select-content"],
  [data-slot="dropdown-menu-content"],
  [data-slot="popover-content"],
  [data-slot="command"] {
    background-color: hsl(var(--surface-3));
    border-color: hsl(var(--line-3));
    box-shadow: var(--sh-2);
  }
  [data-slot="select-item"]:focus,
  [data-slot="dropdown-menu-item"]:focus,
  [data-slot="command-item"][data-selected="true"] {
    background-color: hsl(var(--surface-4));
    color: hsl(var(--ink-1));
  }

  /* Modals are a raised plane. */
  [data-slot="dialog-content"] {
    background-color: hsl(var(--surface-2));
    border-color: hsl(var(--line-2));
    box-shadow: var(--sh-3);
  }
  [data-slot="dialog-overlay"] {
    background-color: var(--overlay-bg);
  }

  /* Tabs → AeVox segmented control. */
  [data-slot="tabs-list"] {
    background-color: hsl(var(--surface-2));
    border: 1px solid hsl(var(--line-2));
    border-radius: var(--radius-sm);
  }
  [data-slot="tabs-trigger"] {
    border-radius: var(--radius-xs);
  }
  [data-slot="tabs-trigger"][data-state="active"] {
    background-color: var(--accent-ghost);
    color: hsl(var(--accent));
    box-shadow: inset 0 0 0 1px var(--accent-line);
  }

  /* Kbd subtle fill. */
  .kbd {
    background-color: hsl(var(--surface-3));
    color: hsl(var(--ink-2));
  }

  /* Table → mono uppercase heads, hairline rows. */
  [data-slot="table-head"] {
    font-family: var(--f-mono);
    font-size: 10.5px;
    font-weight: 700;
    letter-spacing: 0.07em;
    text-transform: uppercase;
    color: hsl(var(--ink-3));
  }
  [data-slot="table-row"] {
    border-color: hsl(var(--line));
  }
  [data-slot="table-row"][data-state="selected"] {
    background-color: var(--accent-ghost);
  }

  /* ---- Badge → every variant is an AeVox mono-uppercase pill ---- */
  [data-slot="badge"][data-variant="live"],
  [data-slot="badge"][data-variant="training"],
  [data-slot="badge"][data-variant="idle"],
  [data-slot="badge"][data-variant="warn"],
  [data-slot="badge"][data-variant="accent"],
  [data-slot="badge"][data-variant="neutral"],
  [data-slot="badge"][data-variant="default"],
  [data-slot="badge"][data-variant="secondary"],
  [data-slot="badge"][data-variant="destructive"],
  [data-slot="badge"][data-variant="outline"] {
    font-family: var(--f-mono);
    font-size: 10px;
    font-weight: 600;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    padding: 2px 7px;
    border-radius: var(--radius-pill);
  }
  [data-slot="badge"][data-variant="default"] {
    background: var(--accent-ghost);
    color: hsl(var(--accent));
    border-color: var(--accent-line);
  }
  [data-slot="badge"][data-variant="secondary"] {
    background: hsl(var(--surface-3));
    color: hsl(var(--ink-2));
    border-color: hsl(var(--line-2));
  }
  [data-slot="badge"][data-variant="destructive"] {
    background: var(--warn-ghost);
    color: hsl(var(--warn));
    border-color: color-mix(in srgb, hsl(var(--warn)) 28%, transparent);
  }
  [data-slot="badge"][data-variant="outline"] {
    background: transparent;
    color: hsl(var(--ink-2));
    border-color: hsl(var(--line-3));
  }
  [data-slot="badge"][data-variant="live"] {
    background: var(--live-ghost);
    color: hsl(var(--live));
    border-color: color-mix(in srgb, hsl(var(--live)) 28%, transparent);
  }
  [data-slot="badge"][data-variant="training"] {
    background: var(--train-ghost);
    color: hsl(var(--train));
    border-color: color-mix(in srgb, hsl(var(--train)) 28%, transparent);
  }
  [data-slot="badge"][data-variant="idle"] {
    background: var(--idle-ghost);
    color: hsl(var(--idle));
    border-color: color-mix(in srgb, hsl(var(--idle)) 28%, transparent);
  }
  [data-slot="badge"][data-variant="warn"] {
    background: var(--warn-ghost);
    color: hsl(var(--warn));
    border-color: color-mix(in srgb, hsl(var(--warn)) 28%, transparent);
  }
  [data-slot="badge"][data-variant="accent"] {
    background: var(--accent-ghost);
    color: hsl(var(--accent));
    border-color: var(--accent-line);
  }
  [data-slot="badge"][data-variant="neutral"] {
    background: hsl(var(--surface-3));
    color: hsl(var(--ink-2));
    border-color: hsl(var(--line-2));
  }
  [data-slot="badge"][data-variant="tag"] {
    font-family: var(--f-mono);
    font-size: 10.5px;
    font-weight: 600;
    letter-spacing: 0.03em;
    padding: 2px 8px;
    border-radius: var(--radius-xs);
    background: hsl(var(--surface-3));
    color: hsl(var(--ink-2));
    border-color: hsl(var(--line-2));
  }

  /* ---- Avatar fallback → AeVox gradient orbs ---- */
  [data-slot="avatar-fallback"][data-tone="violet"] {
    background: radial-gradient(circle at 32% 28%, #b3aef9, #7c89f0 70%);
    color: #1a1640;
  }
  [data-slot="avatar-fallback"][data-tone="green"] {
    background: radial-gradient(circle at 32% 28%, #6ef0d8, #1fb89b 70%);
    color: #042820;
  }
  [data-slot="avatar-fallback"][data-tone="amber"] {
    background: radial-gradient(circle at 32% 28%, #ffd680, #e09a1f 70%);
    color: #2e1d00;
  }
  [data-slot="avatar-fallback"][data-tone="gray"] {
    background: radial-gradient(circle at 32% 28%, hsl(var(--line-2)), hsl(var(--line-3)) 75%);
    color: hsl(var(--ink-1));
  }
  [data-slot="avatar-fallback"][data-tone="accent"] {
    background: radial-gradient(circle at 32% 28%, #7ef0ff, hsl(var(--accent-deep)) 75%);
    color: #042b33;
  }

  /* ---- ToggleGroup → AeVox segmented control ---- */
  [data-slot="toggle-group"] {
    background: hsl(var(--surface-2));
    border: 1px solid hsl(var(--line-2));
    border-radius: var(--radius-sm);
    padding: 3px;
    gap: 2px;
  }
  [data-slot="toggle-group-item"] {
    border: 0 !important;
    border-radius: var(--radius-xs) !important;
    background: transparent;
    color: hsl(var(--ink-2));
    font-size: 12.5px;
    font-weight: 600;
  }
  [data-slot="toggle-group-item"]:hover {
    background: transparent;
    color: hsl(var(--ink-1));
  }
  [data-slot="toggle-group-item"][data-state="on"] {
    background: var(--accent-ghost);
    color: hsl(var(--accent));
    box-shadow: inset 0 0 0 1px var(--accent-line);
  }

  /* ---- Standalone Toggle → AeVox chip (pill) ---- */
  [data-slot="toggle"] {
    border: 1px solid hsl(var(--line-2));
    border-radius: var(--radius-pill);
    background: transparent;
    color: hsl(var(--ink-2));
    font-size: 12.5px;
    font-weight: 500;
  }
  [data-slot="toggle"]:hover {
    background: transparent;
    color: hsl(var(--ink-1));
    border-color: hsl(var(--line-3));
  }
  [data-slot="toggle"][data-state="on"] {
    background: var(--accent-ghost);
    color: hsl(var(--accent));
    border-color: var(--accent-line);
  }

  /* ---- Structural labels → AeVox mono uppercase eyebrows ---- */
  [data-slot="command-group"] [cmdk-group-heading],
  [data-slot="select-label"],
  [data-slot="dropdown-menu-label"] {
    font-family: var(--f-mono);
    font-size: 10px;
    font-weight: 700;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: hsl(var(--ink-3));
  }

  /* ---- Kbd → physical keycap ---- */
  [data-slot="kbd"] {
    font-family: var(--f-mono);
    font-weight: 600;
    min-width: 1.5em;
    padding: 0.1em 0.45em;
    color: hsl(var(--ink-1));
    background: hsl(var(--surface-2));
    border: 1px solid hsl(var(--line-2));
    border-bottom: 2px solid hsl(var(--line-3));
    border-radius: var(--radius-xs);
    box-shadow:
      0 1px 1.5px rgba(0, 0, 0, 0.16),
      inset 0 1px 0 var(--edge);
  }

  /* ---- Skeleton → AeVox shimmer ---- */
  [data-slot="skeleton"] {
    background: linear-gradient(
      90deg,
      hsl(var(--surface-3)),
      hsl(var(--line-2)),
      hsl(var(--surface-3))
    );
    background-size: 200% 100%;
    animation: skel 1.4s linear infinite;
  }

  /* ---- Elevation & depth ---- */
  [data-slot="card"] {
    background-color: hsl(var(--surface-2));
    border: 1px solid hsl(var(--line-2));
    box-shadow:
      var(--sh-card-hi),
      inset 0 1px 0 var(--edge);
    transition:
      box-shadow 0.18s ease,
      transform 0.18s ease,
      border-color 0.18s ease;
  }
  [data-slot="card"]:hover {
    box-shadow:
      var(--sh-2),
      inset 0 1px 0 var(--edge);
    border-color: hsl(var(--line-3));
    transform: translateY(-1px);
  }

  [data-slot="table-row"]:hover {
    background-color: hsl(var(--surface-3));
  }
}

/* ============================================================
   Scrollbars — themed to the surface, thin, token-driven.
   ============================================================ */
* {
  scrollbar-width: thin;
  scrollbar-color: hsl(var(--line-3)) transparent;
}
::-webkit-scrollbar {
  width: 11px;
  height: 11px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: hsl(var(--line-3));
  border-radius: var(--radius-pill);
  border: 3px solid transparent;
  background-clip: content-box;
}
::-webkit-scrollbar-thumb:hover {
  background: hsl(var(--ink-3));
  background-clip: content-box;
}
::-webkit-scrollbar-corner {
  background: transparent;
}

/* ============================================================
   Demo stage — a recessed surface below the cards/canvas.
   ============================================================ */
.ae-scope {
  position: relative;
  background-color: hsl(var(--stage));
  box-shadow: inset 0 1px 4px rgba(0, 0, 0, 0.14);
}

/* ============================================================
   Gallery hero — the AeVox sonar "ping" signature.
   ============================================================ */
.ae-hero-sonar {
  position: relative;
  display: grid;
  place-items: center;
  width: 152px;
  height: 152px;
}
.ae-hero-sonar .core {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: hsl(var(--accent));
  box-shadow:
    0 0 26px var(--accent-glow),
    0 0 0 7px var(--accent-ghost);
}
.ae-hero-sonar .ring {
  position: absolute;
  width: 152px;
  height: 152px;
  border-radius: 50%;
  border: 1.5px solid hsl(var(--accent));
}
.ae-hero-sonar .base {
  opacity: 0.2;
}
.ae-hero-sonar .base.b1 {
  transform: scale(0.42);
  opacity: 0.4;
}
.ae-hero-sonar .base.b2 {
  transform: scale(0.72);
}
.ae-hero-sonar .ping {
  opacity: 0;
  animation: ae-ping 3.2s cubic-bezier(0.2, 0.55, 0.3, 1) infinite;
}
.ae-hero-sonar .ping.p2 {
  animation-delay: 1.06s;
}
.ae-hero-sonar .ping.p3 {
  animation-delay: 2.13s;
}
@keyframes ae-ping {
  0% {
    transform: scale(0.28);
    opacity: 0.55;
  }
  70% {
    opacity: 0.08;
  }
  100% {
    transform: scale(1);
    opacity: 0;
  }
}
@media (prefers-reduced-motion: reduce) {
  .ae-hero-sonar .ping {
    animation: none;
    opacity: 0;
  }
  .ae-hero-sonar .base {
    opacity: 0.32;
  }
}
